using System.Globalization; using System.Text.Json; using Microsoft.Win32;
namespace SoraV2BatteryTip;
internal sealed class AppPaths { public string DataDirectory { get; } public string SoundsDirectory { get; } public string SettingsPath { get; } public string HistoryPath { get; } private string[] LegacyDataDirectories { get; } public AppPaths() { var localDocs=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),"Documents"); var docs=Directory.Exists(localDocs)?localDocs:Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments); DataDirectory=Path.Combine(docs,"SoraV2BatteryTip"); SoundsDirectory=Path.Combine(DataDirectory,"sounds"); SettingsPath=Path.Combine(DataDirectory,"settings.json"); HistoryPath=Path.Combine(DataDirectory,"battery-history.jsonl"); LegacyDataDirectories=new[]{Path.Combine(docs,"MouseBatteryGuard"),Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments),"MouseBatteryGuard")}; } public void Ensure() { Directory.CreateDirectory(DataDirectory); Directory.CreateDirectory(SoundsDirectory); MigrateLegacyData(); var assets=Path.Combine(AppContext.BaseDirectory,"Assets"); if(Directory.Exists(assets)){ foreach(var src in Directory.GetFiles(assets,"*.wav",SearchOption.TopDirectoryOnly)){ var dst=Path.Combine(SoundsDirectory,Path.GetFileName(src)); if(!File.Exists(dst)) File.Copy(src,dst,false); } } } private void MigrateLegacyData(){ foreach(var legacy in LegacyDataDirectories){ try{ if(string.Equals(Path.GetFullPath(legacy).TrimEnd('\\','/'),Path.GetFullPath(DataDirectory).TrimEnd('\\','/'),StringComparison.OrdinalIgnoreCase))continue; if(!Directory.Exists(legacy))continue; var legacySettings=Path.Combine(legacy,"settings.json"); if(File.Exists(legacySettings)&&!File.Exists(SettingsPath))File.Copy(legacySettings,SettingsPath,false); var legacySounds=Path.Combine(legacy,"sounds"); if(Directory.Exists(legacySounds)){ foreach(var src in Directory.GetFiles(legacySounds,"*.wav",SearchOption.TopDirectoryOnly)){ var dst=Path.Combine(SoundsDirectory,Path.GetFileName(src)); if(!File.Exists(dst))File.Copy(src,dst,false); } } }catch{} } } }
internal sealed class SettingsStore { private readonly AppPaths _paths; private static readonly JsonSerializerOptions JsonOptions=new(){WriteIndented=true}; public SettingsStore(AppPaths paths)=>_paths=paths; public AppSettings Load(){ try{ if(File.Exists(_paths.SettingsPath)) return JsonSerializer.Deserialize<AppSettings>(File.ReadAllText(_paths.SettingsPath))??new AppSettings(); }catch{} var s=new AppSettings{Language=CultureInfo.CurrentUICulture.Name.StartsWith("zh")?"zh-CN":"en-US"}; Save(s); return s;} public void Save(AppSettings settings){ _paths.Ensure(); File.WriteAllText(_paths.SettingsPath,JsonSerializer.Serialize(settings,JsonOptions)); StartupManager.SetEnabled(settings.StartupWithWindows);} }
internal static class StartupManager { private const string RunKey=@"Software\Microsoft\Windows\CurrentVersion\Run"; private const string StartupApprovedRunKey=@"Software\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\Run"; public static void SetEnabled(bool enabled){ try{ using var key=Registry.CurrentUser.OpenSubKey(RunKey,true)??Registry.CurrentUser.CreateSubKey(RunKey,true); if(enabled){ key.SetValue("SoraV2BatteryTip",$"\"{Application.ExecutablePath}\""); key.DeleteValue("MouseBatteryGuard",false); DeleteStartupApproved("MouseBatteryGuard");} else { key.DeleteValue("SoraV2BatteryTip",false); key.DeleteValue("MouseBatteryGuard",false); DeleteStartupApproved("SoraV2BatteryTip"); DeleteStartupApproved("MouseBatteryGuard");} }catch{} } private static void DeleteStartupApproved(string valueName){ try{ using var key=Registry.CurrentUser.OpenSubKey(StartupApprovedRunKey,true); key?.DeleteValue(valueName,false); }catch{} } }

